// RecordRequest records metrics for a completed request with full validation
func (mc *MetricsCollector) RecordRequest(userID, method, endpoint, statusCode string, duration time.Duration) error {
	sanitizedUser, err := sanitizeLabel(userID)
	if err != nil {
		mc.rejectedLabels.Inc()
		return fmt.Errorf("invalid user_id label: %w", err)
	}

	sanitizedEndpoint, err := sanitizeLabel(endpoint)
	if err != nil {
		mc.rejectedLabels.Inc()
		return fmt.Errorf("invalid endpoint label: %w", err)
	}

	sanitizedMethod, err := sanitizeLabel(method)
	if err != nil {
		mc.rejectedLabels.Inc()
		return fmt.Errorf("invalid method label: %w", err)
	}

	sanitizedStatus, err := sanitizeLabel(statusCode)
	if err != nil {
		mc.rejectedLabels.Inc()
		return fmt.Errorf("invalid status_code label: %w", err)
	}

	// Check cardinality limits
	userKey := fmt.Sprintf("%s:%s:%s", sanitizedUser, sanitizedMethod, sanitizedEndpoint)
	if !mc.userTracker.Allow(userKey) {
		mc.rejectedLabels.Inc()
		return fmt.Errorf("cardinality limit reached: too many unique user/method/endpoint combinations")
	}

	if !mc.endpointTracker.Allow(sanitizedEndpoint) {
		mc.rejectedLabels.Inc()
		return fmt.Errorf("cardinality limit reached: too many unique endpoints")
	}

	mc.requestsTotal.WithLabelValues(sanitizedUser, sanitizedMethod, sanitizedEndpoint, sanitizedStatus).Inc()
	mc.requestDuration.WithLabelValues(sanitizedUser, sanitizedMethod, sanitizedEndpoint).Observe(duration.Seconds())
	mc.trackerSize.Set(float64(mc.userTracker.Size()))

	return nil
}

