// instrumentedHandler wraps an HTTP handler with per-user, per-request metrics
func instrumentedHandler(mc *MetricsCollector, next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = "anonymous"
		}

		endpoint := r.URL.Path
		method := r.Method

		_ = mc.TrackInFlight(userID, 1)
		defer func() {
			_ = mc.TrackInFlight(userID, -1)
		}()

		recorder := &statusRecorder{ResponseWriter: w, statusCode: http.StatusOK}
		start := time.Now()

		next.ServeHTTP(recorder, r)

		duration := time.Since(start)
		statusCode := fmt.Sprintf("%d", recorder.statusCode)

		if err := mc.RecordRequest(userID, method, endpoint, statusCode, duration); err != nil {
			log.Printf("Warning: failed to record metrics: %v", err)
		}

		if recorder.statusCode >= 400 {
			errorType := "client_error"
			if recorder.statusCode >= 500 {
				errorType = "server_error"
			}
			if err := mc.RecordError(userID, method, endpoint, errorType); err != nil {
				log.Printf("Warning: failed to record error metrics: %v", err)
			}
		}
	}
}

// statusRecorder captures the HTTP status code from the response
type statusRecorder struct {
	http.ResponseWriter
	statusCode int
}

func (sr *statusRecorder) WriteHeader(code int) {
	sr.statusCode = code
	sr.ResponseWriter.WriteHeader(code)
}

func handleAPI(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	_, _ = w.Write([]byte(`{"status":"ok"}`))
}

func handleHealth(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	_, _ = w.Write([]byte(`{"healthy":true}`))
}

func main() {
	registry := prometheus.NewRegistry()

	// Register default Go metrics
	registry.MustRegister(prometheus.NewGoCollector())
	registry.MustRegister(prometheus.NewProcessCollector(prometheus.ProcessCollectorOpts{}))

	mc := NewMetricsCollector(registry)

	mux := http.NewServeMux()

	mux.HandleFunc("/api/data", instrumentedHandler(mc, handleAPI))
	mux.HandleFunc("/api/health", instrumentedHandler(mc, handleHealth))

	// Metrics endpoint uses the custom registry
	mux.Handle("/metrics", promhttp.HandlerFor(registry, promhttp.HandlerOpts{
		EnableOpenMetrics: true,
	}))

	server := &http.Server{
		Addr:              ":8080",
		Handler:           mux,
		ReadTimeout:       10 * time.Second,
		ReadHeaderTimeout: 5 * time.Second,
		WriteTimeout:      10 * time.Second,
		IdleTimeout:       120 * time.Second,
		MaxHeaderBytes:    1 << 20, // 1 MB
	}

	log.Println("Starting server on :8080")
	log.Println("Metrics available at /metrics")
	log.Println("API endpoints: /api/data, /api/health")
	log.Printf("Cardinality limits: %d unique label combinations, 1000 unique endpoints", maxUniqueLabelValues)

	if err := server.ListenAndServe(); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}